---

### Lifecycle State Machine

```
New() в”Җв”Җв–ә RUNNING в”Җв”Җв–ә Shutdown()      в”Җв”Җв–ә DRAINING в”Җв”Җв–ә (queue empty) в”Җв”Җв–ә STOPPED
                 в””в”Җв”Җв–ә ForceShutdown() в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв–ә STOPPED
```

---

### Key Design Decisions & Rationale

1. **`close(jobChan)` triggers graceful drain** вҖ” workers range over the channel after close, finish all queued jobs, then exit naturally.
2. **`context.cancel()` triggers force shutdown** вҖ” workers also `select` on `ctx.Done()`, so they can abandon a blocked receive immediately.
3. **`sync.Once` for idempotency** вҖ” calling `Shutdown()` or `ForceShutdown()` multiple times is completely safe.
4. **Atomic state guard on `Submit()`** вҖ” checked *before* sending to the channel, so no send-on-closed-channel panic.
5. **`WaitGroup`** вҖ” `wg.Add(1)` per worker at start; `wg.Done()` in a deferred call inside each worker. Both `Shutdown` variants call `wg.Wait()`.

---

## вң… Full Implementation

```go
package workerpool

import (
	"context"
	"fmt"
	"sync"
	"sync/atomic"
	"time"
)

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

// Job is the unit of work submitted to the pool.
// Handler is called by a worker; any result/error should be handled inside it.
type Job struct {
	ID      int
	Handler func() // The actual work
}

// poolState represents the lifecycle of the pool.
type poolState int32

const (
	stateRunning      poolState = iota // accepting new jobs
	stateShuttingDown                  // draining; no new jobs accepted
	stateStopped                       // fully stopped
)

// WorkerPool is a bounded, concurrent worker pool with graceful shutdown.
type WorkerPool struct {
	jobChan chan Job        // bounded job queue
	wg      sync.WaitGroup // tracks all worker goroutines
	ctx     context.Context
	cancel  context.CancelFunc
	once    sync.Once    // guarantees shutdown logic runs exactly once
	state   atomic.Int32 // holds a poolState value
}

// ---------------------------------------------------------------------------
// Constructor
// ---------------------------------------------------------------------------

// New creates a WorkerPool with `numWorkers` goroutines and a job queue
// of capacity `queueSize`. Both values must be > 0.
func New(numWorkers, queueSize int) *WorkerPool {
	if numWorkers <= 0 || queueSize <= 0 {
		panic("workerpool: numWorkers and queueSize must be > 0")
	}

	ctx, cancel := context.WithCancel(context.Background())

	p := &WorkerPool{
		jobChan: make(chan Job, queueSize),
		ctx:     ctx,
		cancel:  cancel,
	}
	p.state.Store(int32(stateRunning))

	// Spawn workers
	for i := 0; i < numWorkers; i++ {
		p.wg.Add(1)
		go p.worker(i)
	}

	return p
}

// ---------------------------------------------------------------------------
// Worker goroutine
// ---------------------------------------------------------------------------

// worker is the long-lived goroutine that processes jobs.
// It exits when:
//   (a) jobChan is closed AND drained  вҶ’ graceful shutdown
//   (b) ctx is cancelled               вҶ’ force shutdown
func (p *WorkerPool) worker(id int) {
	defer p.wg.Done()

	for {
		select {
		// Force-shutdown: context cancelled вҖ” abandon any blocked receive
		case <-p.ctx.Done():
			fmt.Printf("[worker %d] force-stopped\n", id)
			return

		// Normal path: receive a job, or exit cleanly when channel is closed
		case job, ok := <-p.jobChan:
			if !ok {
				// Channel closed вҶ’ graceful shutdown drain complete
				fmt.Printf("[worker %d] channel closed, exiting\n", id)
				return
			}
			fmt.Printf("[worker %d] starting job %d\n", id, job.ID)
			job.Handler()
			fmt.Printf("[worker %d] finished job %d\n", id, job.ID)
		}
	}
}

// ---------------------------------------------------------------------------
// Submit
// ---------------------------------------------------------------------------

// ErrPoolShutdown is returned when Submit is called on a stopped pool.
var ErrPoolShutdown = fmt.Errorf("workerpool: pool is shutting down or stopped")

// Submit enqueues a job. It blocks if the queue is full (backpressure).
// Returns ErrPoolShutdown if the pool is no longer accepting work.
func (p *WorkerPool) Submit(job Job) error {
	if poolState(p.state.Load()) != stateRunning {
		return ErrPoolShutdown
	}

	// Double-check after the state read to minimise the race window.
	// A send on a closed channel is still guarded: we only close jobChan
	// inside once.Do, which also sets state to shuttingDown first.
	select {
	case p.jobChan <- job:
		return nil
	case <-p.ctx.Done():
		return ErrPoolShutdown
	}
}

// TrySubmit is a non-blocking variant of Submit.
// Returns false immediately if the queue is full or the pool is shut down.
func (p *WorkerPool) TrySubmit(job Job) (bool, error) {
	if poolState(p.state.Load()) != stateRunning {
		return false, ErrPoolShutdown
	}
	select {
	case p.jobChan <- job:
		return true, nil
	default:
		return false, nil // queue full
	}
}

// ---------------------------------------------------------------------------
// Shutdown (graceful)
// ---------------------------------------------------------------------------

// Shutdown stops accepting new jobs and waits for all queued and in-flight
// jobs to complete before returning. Safe to call multiple times.
func (p *WorkerPool) Shutdown() {
	p.once.Do(func() {
		// 1. Mark as draining вҖ” Submit() will now reject new jobs
		p.state.Store(int32(stateShuttingDown))
		// 2. Close the channel вҖ” workers drain remaining jobs then exit
		close(p.jobChan)
		// 3. Wait for all workers to finish
		p.wg.Wait()
		// 4. Cancel the context (no-op here, but keeps state consistent)
		p.cancel()
		p.state.Store(int32(stateStopped))
		fmt.Println("[pool] graceful shutdown complete")
	})
}

// ---------------------------------------------------------------------------
// ForceShutdown (immediate)
// ---------------------------------------------------------------------------

// ForceShutdown cancels the context immediately, causing workers to stop
// after their current job (if any). Queued-but-unstarted jobs are dropped.
// Waits for all workers to exit before returning. Safe to call multiple times.
func (p *WorkerPool) ForceShutdown() {
	p.once.Do(func() {
		p.state.Store(int32(stateShuttingDown))
		// Cancel context first вҖ” workers unblock from their select
		p.cancel()
		// Close the channel so no further sends are possible
		close(p.jobChan)
		p.wg.Wait()
		p.state.Store(int32(stateStopped))
		fmt.Println("[pool] force shutdown complete")
	})
}

// ---------------------------------------------------------------------------
// ShutdownWithTimeout вҖ” convenience wrapper
// ---------------------------------------------------------------------------

// ShutdownWithTimeout attempts a graceful shutdown but falls back to
// ForceShutdown if workers haven't finished within the deadline.
func (p *WorkerPool) ShutdownWithTimeout(timeout time.Duration) {
	done := make(chan struct{})
	go func() {
		p.Shutdown()
		close(done)
	}()

	select {
	case <-done:
		// Graceful shutdown completed in time
	case <-time.After(timeout):
		fmt.Println("[pool] timeout exceeded вҖ” forcing shutdown")
		p.ForceShutdown()
	}
}
```

